class Solution {
    public char kthCharacter(long k, int[] operations) {
        int m = operations.length;
        int exponent = m;
        int shifts = 0;

        for (int i = m - 1; i >= 0; i--) {
            int op = operations[i];
            if (exponent == 0) {
                break;
            }
            if (exponent - 1 <= 47) {
                long L_prev = 1L << (exponent - 1);
                if (op == 0) {
                    if (k > L_prev) {
                        k -= L_prev;
                    }
                } else {
                    if (k > L_prev) {
                        shifts++;
                        k -= L_prev;
                    }
                }
            }
            exponent--;
        }
        return (char) ('a' + (shifts % 26));
    }
}

